var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"탄창!","JPN":"弾倉！","ENG":"Ammo!","TWN":"彈匣！"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"말해 두겠는데, 이제 세 개 남았다.","JPN":"言っておくが、残りはあと3つだ。","ENG":"Just so you know, there’s only three mags left.","TWN":"現在就剩三個了。"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"제기랄. 저놈들 끝이 없어 보이는데. ","JPN":"クソ、キリがないな。","ENG":"Damn... There’s no end to them. ","TWN":"可惡！那些傢伙看起來沒完沒了。"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"이상해. 여기에 이렇게 많은 침식체가 있을 리 없어.","JPN":"なにかおかしい。ここにこんな侵食体が多いはずがない。","ENG":"Something is off. There’s no way there'd be so many C.O.'s here.","TWN":"太奇怪了， 這裡不可能有這麼多的侵蝕體啊。"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"하지만 있잖아?","JPN":"でも、実際にいるじゃねえか？","ENG":"You know what, though?","TWN":"但事實就是如此。"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"윗대가리 놈들, 굳이 우릴 여기에 보낸 걸 보면 뭔가 알고 있었던 거 아냐?","JPN":"わざわざ俺らをここへ向かわせたってことは、お偉いさんたちは何か知ってたんじゃないのか？","ENG":"The top brass must’ve known something if they dispatched us all the way out here.","TWN":"上頭非要把我們送到這裡，難道他們早有什麼打算了？"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"......뭐, 그렇겠지. 우리에게 친절하게 설명해 줄 이유는 없으니까.","JPN":"……まあ、そうだろうな。だが企業のやつらは、わざわざ俺たちに説明する理由がない。","ENG":"I bet. And they had no reason to explain everything to us either.","TWN":"……也許。 畢竟他們也沒有理由給我們詳細地說明。"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"......개자식들.","JPN":"……ちくしょう。","ENG":"Those bastards.","TWN":"……這群雜碎！"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"수다 시간은 끝이다!","JPN":"おしゃべりはもう十分だ！","ENG":"Enough chatting!","TWN":"聊天時間結束了！"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"어이! 수리는 멀었나?","JPN":"おい！　修理はまだか？","ENG":"Hey! Are we there yet?","TWN":"喂！還沒好嗎？"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"......내 전공은 통신병이 아니라 다른 놈들 대가리에 총알 박아 넣는 거거든?!","JPN":"……私の専門は通信じゃなくて、撃つことなの！","ENG":"I’m not a radioman by trade... I specialize in putting bullets in skulls, alright?","TWN":"……我的專業不是通訊兵，而是把子彈打進那些傢伙的腦袋裡！"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"전공 살리기 전에 좀 닥쳐 줄래?!","JPN":"頭、ぶち抜かれたくなかったら黙ってて！","ENG":"So shut up before I decide to practice my specialty on you!","TWN":"在我發揮我的專業前先閉嘴好嗎？"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"제기랄!","JPN":"クソ！","ENG":"Damn it!","TWN":"可惡！"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"그래도 정기 연락이 끊겼으니까 접선지에서 기다리던 카운터가 이쪽으로 오고 있을 거야!","JPN":"定期連絡が途切れたんだ、合流地点で待機してるカウンターがこっちへ向かうはずだろ！","ENG":"Still, they must've realized something went wrong when we stopped calling in. Maybe the Counter is on the way here from the rendezvous point?","TWN":"定期聯絡斷了，在會合處等待的制裁者應該會往這邊來的！"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"카운터가 오면 해 볼 만하지 않을까?","JPN":"カウンターが来れば、どうにかなるだろ！？","ENG":"We might have a shot with a Counter here, no?","TWN":"制裁者來了的話，應該能拼一下吧？"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"......생각 없는 놈은 행복해서 좋겠군.","JPN":"……バカはのんきで羨ましいな。","ENG":"Ignorance is bliss, I guess...","TWN":"……真羡慕你們這些沒腦袋的傻瓜。"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};